              "      JOIN `main`.`bi_output`.`bi_output_vg_customer_snapshot_test` c\r\n",
              "        ON r.`DateID` >= c.`DateID`\r\n",
              "        AND r.`DateID` <= c.`DateID`\r\n",
              "        AND r.`RealCID` = c.`RealCID`\r\n",
              "  WHERE\r\n",
              "    YEAR(r.`Date`) = 2024\r\n",
              "    AND `IncludedInTotalRevenue` = true\r\n",
              "\t\tAND c.`Country` = 'Germany'\r\n",
              "),\r\n",
              "deposits_cte AS (\r\n",
              "  SELECT\r\n",
              "    SUM(`GlobalDepositsAmount`) AS total_deposits\r\n",
              "  FROM\r\n",
              "        `main`.`bi_output`.`bi_output_vg_mimo` m\r\n",
              "      JOIN `main`.`bi_output`.`bi_output_vg_customer_snapshot_test` c\r\n",
              "        ON m.`DateID` >= c.`DateID`\r\n",
              "        AND m.`DateID` <= c.`DateID`\r\n",
              "        AND m.`RealCID` = c.`RealCID`\r\n",
              "  WHERE\r\n",
              "    YEAR(CAST(m.`Date` AS DATE)) = 2024\r\n",
              "\t\tand c.Country = 'Germany'\r\n",
              ")\r\n",
              "SELECT\r\n",
              "  r.total_revenue,\r\n",
              "  d.total_deposits\r\n",
              "FROM\r\n",
              "  revenue_cte r CROSS JOIN deposits_cte d\r\n"
            ]
          }
